sealed class DeviceTrustLevel {
    object Trusted : DeviceTrustLevel()
    data class Degraded(val reasons: List<String>) : DeviceTrustLevel()
    data class Untrusted(val reasons: List<String>) : DeviceTrustLevel()
}

sealed class SecurityException : Exception() {
    data class DeviceCompromised(val details: String) : SecurityException()
    data class IntegrityCheckFailed(val details: String) : SecurityException()
    data class EncryptionError(val details: String) : SecurityException()
    data class AuthenticationRequired(val details: String) : SecurityException()
    data class TransactionLimitExceeded(val details: String) : SecurityException()
