    data class TamperingDetected(val details: String) : SecurityException()
}

class DeviceIntegrityChecker(private val context: Context) {

    private val tag = "DeviceIntegrity"

    fun assessTrustLevel(): DeviceTrustLevel {
        val issues = mutableListOf<String>()

        if (isRooted()) issues.add("ROOTED_DEVICE")
        if (isEmulator()) issues.add("EMULATOR_DETECTED")
        if (isDebuggable()) issues.add("DEBUGGABLE_BUILD")
        if (isAdbEnabled()) issues.add("ADB_ENABLED")
        if (hasHookingFrameworks()) issues.add("HOOKING_FRAMEWORK_DETECTED")
        if (isRunningOnVirtualDevice()) issues.add("VIRTUAL_DEVICE")
        if (!isScreenLockEnabled()) issues.add("NO_SCREEN_LOCK")
        if (hasUnsafeApps()) issues.add("UNSAFE_APPS_INSTALLED")

        return when {
            issues.any { it in criticalIssues } -> DeviceTrustLevel.Untrusted(issues)
            issues.isNotEmpty() -> DeviceTrustLevel.Degraded(issues)
            else -> DeviceTrustLevel.Trusted
        }
    }

    private val criticalIssues = setOf(
        "ROOTED_DEVICE",
        "HOOKING_FRAMEWORK_DETECTED",
        "TAMPERED_APK"
    )

    fun isRooted(): Boolean {
        val rootIndicators = listOf(
            "/system/app/Superuser.apk",
            "/sbin/su",
            "/system/bin/su",
            "/system/xbin/su",
            "/data/local/xbin/su",
            "/data/local/bin/su",
            "/system/sd/xbin/su",
            "/system/bin/failsafe/su",
            "/data/local/su",
            "/su/bin/su",
            "/system/app/SuperSU.apk",
            "/system/app/SuperSU",
            "/system/app/Magisk.apk"
        )

        for (path in rootIndicators) {
            if (File(path).exists()) {
                Log.w(tag, "Root indicator found: $path")
                return true
            }
        }

        // Check for su binary in PATH
        val paths = System.getenv("PATH")?.split(":") ?: emptyList()
        for (path in paths) {
            if (File(path, "su").exists()) {
                return true
            }
        }

        // Check build tags
        val buildTags = Build.TAGS
        if (buildTags != null && buildTags.contains("test-keys")) {
            return true
        }

        // Try executing su
        return try {
            val process = Runtime.getRuntime().exec(arrayOf("which", "su"))
            process.inputStream.bufferedReader().readLine() != null
        } catch (e: Exception) {
            false
        }
    }

    fun isEmulator(): Boolean {
        return (Build.FINGERPRINT.startsWith("generic")
                || Build.FINGERPRINT.startsWith("unknown")
                || Build.MODEL.contains("google_sdk")
                || Build.MODEL.contains("Emulator")
                || Build.MODEL.contains("Android SDK built for x86")
                || Build.BOARD == "QC_Reference_Phone"
                || Build.MANUFACTURER.contains("Genymotion")
                || Build.HOST.startsWith("Build")
                || (Build.BRAND.startsWith("generic") && Build.DEVICE.startsWith("generic"))
                || "google_sdk" == Build.PRODUCT
                || Build.HARDWARE.contains("goldfish")
                || Build.HARDWARE.contains("ranchu"))
    }

    private fun isDebuggable(): Boolean {
        return (context.applicationInfo.flags and android.content.pm.ApplicationInfo.FLAG_DEBUGGABLE) != 0
    }

    private fun isAdbEnabled(): Boolean {
        return try {
            Settings.Global.getInt(context.contentResolver, Settings.Global.ADB_ENABLED, 0) == 1
        } catch (e: Exception) {
            false
        }
    }

    private fun hasHookingFrameworks(): Boolean {
        val hookingPackages = listOf(
            "de.robv.android.xposed",
            "de.robv.android.xposed.installer",
            "com.saurik.substrate",
            "io.va.exposed",
            "org.meowcat.edxposed.manager",
            "com.topjohnwu.magisk",
            "me.weishu.exp"
        )

        val pm = context.packageManager
        for (pkg in hookingPackages) {
            try {
                pm.getPackageInfo(pkg, 0)
                return true
            } catch (e: Exception) {
                // Package not found, continue
            }
        }

        // Check for Xposed in stack trace
        try {
            throw Exception("Check stack")
        } catch (e: Exception) {
            for (element in e.stackTrace) {
                if (element.className.contains("xposed", ignoreCase = true)) {
                    return true
                }
            }
        }

        return false
    }

    private fun isRunningOnVirtualDevice(): Boolean {
        val files = listOf(
            "/dev/vboxguest",
            "/dev/vboxuser",
            "/proc/tty/drivers"
        )
        return files.any { path ->
            try {
                val file = File(path)
                file.exists() && file.readText().contains("vbox", ignoreCase = true)
            } catch (e: Exception) {
                false
            }
        }
    }

    private fun isScreenLockEnabled(): Boolean {
        val keyguardManager = context.getSystemService(Context.KEYGUARD_SERVICE) as? android.app.KeyguardManager
        return keyguardManager?.isDeviceSecure ?: false
    }

    private fun hasUnsafeApps(): Boolean {
        val unsafeApps = listOf(
            "com.koushikdutta.superuser",
            "eu.chainfire.supersu",
            "com.thirdparty.superuser",
            "com.yellowes.su"
        )
        val pm = context.packageManager
        return unsafeApps.any { pkg ->
            try {
                pm.getPackageInfo(pkg, 0)
                true
            } catch (e: Exception) {
                false
            }
        }
    }

    suspend fun verifyPlayIntegrity(nonce: String): Result<String> = withContext(Dispatchers.IO) {
        try {
            val integrityManager = IntegrityManagerFactory.create(context)
            val tokenRequest = IntegrityTokenRequest.builder()
                .setNonce(nonce)
                .build()

            val taskResult = CompletableDeferred<Result<String>>()

            integrityManager.requestIntegrityToken(tokenRequest)
                .addOnSuccessListener { response ->
                    taskResult.complete(Result.success(response.token()))
                }
                .addOnFailureListener { exception ->
                    taskResult.complete(Result.failure(
                        SecurityException.IntegrityCheckFailed(exception.message ?: "Unknown error")
                    ))
                }

            taskResult.await()
        } catch (e: Exception) {
            Result.failure(SecurityException.IntegrityCheckFailed(e.message ?: "Integrity check unavailable"))
        }
    }
}

