class SecureEncryptionManager(private val context: Context) {

    companion object {
        private const val KEYSTORE_PROVIDER = "AndroidKeyStore"
        private const val KEY_ALIAS_PAYMENT = "payment_encryption_key"
        private const val KEY_ALIAS_WALLET = "wallet_encryption_key"
        private const val GCM_TAG_LENGTH = 128
        private const val GCM_IV_LENGTH = 12
    }

    private val keyStore: KeyStore = KeyStore.getInstance(KEYSTORE_PROVIDER).apply { load(null) }

    private fun getOrCreateKey(alias: String): SecretKey {
        if (keyStore.containsAlias(alias)) {
            val entry = keyStore.getEntry(alias, null) as KeyStore.SecretKeyEntry
            return entry.secretKey
        }

        val keyGenerator = KeyGenerator.getInstance(
            KeyProperties.KEY_ALGORITHM_AES,
            KEYSTORE_PROVIDER
        )

        val builder = KeyGenParameterSpec.Builder(
            alias,
            KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
        )
            .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
            .setKeySize(256)
            .setUserAuthenticationRequired(false) // We handle auth at transaction level
            .setRandomizedEncryptionRequired(true)

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.N) {
            builder.setInvalidatedByBiometricEnrollment(true)
        }

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            builder.setIsStrongBoxBacked(isStrongBoxAvailable())
        }

        keyGenerator.init(builder.build())
        return keyGenerator.generateKey()
    }

    private fun isStrongBoxAvailable(): Boolean {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            context.packageManager.hasSystemFeature("android.hardware.strongbox_keystore")
        } else {
            false
        }
    }

    fun encrypt(data: ByteArray, keyAlias: String = KEY_ALIAS_PAYMENT): EncryptedData {
        val key = getOrCreateKey(keyAlias)
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        cipher.init(Cipher.ENCRYPT_MODE, key)

        val iv = cipher.iv
        val encryptedBytes = cipher.doFinal(data)

        return EncryptedData(
            ciphertext = encryptedBytes,
            iv = iv,
            keyAlias = keyAlias
        )
    }

    fun decrypt(encryptedData: EncryptedData): ByteArray {
        val key = getOrCreateKey(encryptedData.keyAlias)
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        val spec = GCMParameterSpec(GCM_TAG_LENGTH, encryptedData.iv)
        cipher.init(Cipher.DECRYPT_MODE, key, spec)

        return cipher.doFinal(encryptedData.ciphertext)
    }

    fun encryptString(data: String, keyAlias: String = KEY_ALIAS_PAYMENT): String {
        val encrypted = encrypt(data.toByteArray(Charsets.UTF_8), keyAlias)
        val combined = encrypted.iv + encrypted.ciphertext
        return Base64.encodeToString(combined, Base64.NO_WRAP)
    }

    fun decryptString(encodedData: String, keyAlias: String = KEY_ALIAS_PAYMENT): String {
        val combined = Base64.decode(encodedData, Base64.NO_WRAP)
        val iv = combined.sliceArray(0 until GCM_IV_LENGTH)
        val ciphertext = combined.sliceArray(GCM_IV_LENGTH until combined.size)

        val encryptedData = EncryptedData(ciphertext, iv, keyAlias)
        return String(decrypt(encryptedData), Charsets.UTF_8)
    }

    fun hashSensitiveData(data: String): String {
        val salt = SecureRandom().let { random ->
            ByteArray(32).also { random.nextBytes(it) }
        }
        val digest = MessageDigest.getInstance("SHA-256")
        digest.update(salt)
        val hash = digest.digest(data.toByteArray(Charsets.UTF_8))
        return Base64.encodeToString(salt + hash, Base64.NO_WRAP)
    }

    fun wipeKey(alias: String) {
        if (keyStore.containsAlias(alias)) {
            keyStore.deleteEntry(alias)
        }
    }
}

data class EncryptedData(
    val ciphertext: ByteArray,
    val iv: ByteArray,
    val keyAlias: String
) {
    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other !is EncryptedData) return false
        return ciphertext.contentEquals(other.ciphertext) &&
                iv.contentEquals(other.iv) &&
                keyAlias == other.keyAlias
    }

    override fun hashCode(): Int {
        var result = ciphertext.contentHashCode()
        result = 31 * result + iv.contentHashCode()
        result = 31 * result + keyAlias.hashCode()
        return result
    }
}

