class SecureStorageManager(private val context: Context) {

    private val masterKey = MasterKey.Builder(context)
        .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
        .build()

    private val securePrefs by lazy {
        EncryptedSharedPreferences.create(
            context,
            "secure_payment_prefs",
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    fun storeSecurely(key: String, value: String) {
        securePrefs.edit().putString(key, value).apply()
    }

    fun retrieveSecurely(key: String): String? {
        return securePrefs.getString(key, null)
    }

    fun removeSecurely(key: String) {
        securePrefs.edit().remove(key).apply()
    }

    fun clearAll() {
        securePrefs.edit().clear().apply()
    }

    fun storeWalletBalance(userId: String, balance: BigDecimal) {
        storeSecurely("wallet_balance_$userId", balance.toPlainString())
    }

    fun getWalletBalance(userId: String): BigDecimal {
        val stored = retrieveSecurely("wallet_balance_$userId")
        return stored?.toBigDecimalOrNull() ?: BigDecimal.ZERO
    }
}

