class BiometricAuthManager(private val activity: FragmentActivity) {

    fun canAuthenticate(): BiometricCapability {
        val biometricManager = BiometricManager.from(activity)

        val strongResult = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)
        if (strongResult == BiometricManager.BIOMETRIC_SUCCESS) {
            return BiometricCapability.STRONG_BIOMETRIC
        }

        val weakResult = biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_WEAK)
        if (weakResult == BiometricManager.BIOMETRIC_SUCCESS) {
            return BiometricCapability.WEAK_BIOMETRIC
        }

        val deviceCredential = biometricManager.canAuthenticate(BiometricManager.Authenticators.DEVICE_CREDENTIAL)
        if (deviceCredential == BiometricManager.BIOMETRIC_SUCCESS) {
            return BiometricCapability.DEVICE_CREDENTIAL
        }

        return BiometricCapability.NONE
    }

    fun authenticate(
        title: String = "Authenticate Payment",
        subtitle: String = "Verify your identity to proceed",
        onSuccess: () -> Unit,
        onError: (Int, String) -> Unit,
        onFailed: () -> Unit
    ) {
        val executor = ContextCompat.getMainExecutor(activity)

        val callback = object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                onSuccess()
            }

            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                onError(errorCode, errString.toString())
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                onFailed()
            }
        }

        val biometricPrompt = BiometricPrompt(activity, executor, callback)

        val capability = canAuthenticate()
        val authenticators = when (capability) {
            BiometricCapability.STRONG_BIOMETRIC ->
                BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.DEVICE_CREDENTIAL
            BiometricCapability.WEAK_BIOMETRIC ->
                BiometricManager.Authenticators.BIOMETRIC_WEAK or BiometricManager.Authenticators.DEVICE_CREDENTIAL
            BiometricCapability.DEVICE_CREDENTIAL ->
                BiometricManager.Authenticators.DEVICE_CREDENTIAL
            BiometricCapability.NONE -> {
                onError(-1, "No authentication method available")
                return
            }
        }

        val promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle(title)
            .setSubtitle(subtitle)
            .setAllowedAuthenticators(authenticators)
            .build()

        biometricPrompt.authenticate(promptInfo)
    }
}

enum class BiometricCapability {
    STRONG_BIOMETRIC,
    WEAK_BIOMETRIC,
    DEVICE_CREDENTIAL,
    NONE
}

// ============================================================
// Rate Limiter & Anti-Fraud
// ============================================================

class TransactionRateLimiter {

    private val transactionTimestamps = ConcurrentHashMap<String, MutableList<Long>>()
    private val failedAttempts = ConcurrentHashMap<String, Int>()

    companion object {
        private const val MAX_TRANSACTIONS_PER_MINUTE = 5
        private const val MAX_TRANSACTIONS_PER_HOUR = 30
        private const val MAX_FAILED_ATTEMPTS = 3
        private const val LOCKOUT_DURATION_MS = 30 * 60 * 1000L // 30 minutes
        private const val MINUTE_MS = 60 * 1000L
        private const val HOUR_MS = 60 * 60 * 1000L
    }

    private val lockoutTimestamps = ConcurrentHashMap<String, Long>()

    fun checkRateLimit(userId: String): RateLimitResult {
        val now = System.currentTimeMillis()

        // Check lockout
        val lockoutTime = lockoutTimestamps[userId]
        if (lockoutTime != null && now - lockoutTime < LOCKOUT_DURATION_MS) {
            val remainingMs = LOCKOUT_DURATION_MS - (now - lockoutTime)
            return RateLimitResult.LockedOut(remainingMs)
        } else if (lockoutTime != null) {
            lockoutTimestamps.remove(userId)
            failedAttempts.remove(userId)
        }

        val timestamps = transactionTimestamps.getOrPut(userId) { mutableListOf() }

        // Clean old timestamps
        timestamps.removeAll { now - it > HOUR_MS }

        val lastMinuteCount = timestamps.count { now - it < MINUTE_MS }
        val lastHourCount = timestamps.size

        return when {
            lastMinuteCount >= MAX_TRANSACTIONS_PER_MINUTE ->
                RateLimitResult.ExceededPerMinute(MAX_TRANSACTIONS_PER_MINUTE)
            lastHourCount >= MAX_TRANSACTIONS_PER_HOUR ->
                RateLimitResult.ExceededPerHour(MAX_TRANSACTIONS_PER_HOUR)
            else -> RateLimitResult.Allowed
        }
    }

    fun recordTransaction(userId: String) {
        val timestamps = transactionTimestamps.getOrPut(userId) { mutableListOf() }
        timestamps.add(System.currentTimeMillis())
    }

    fun recordFailedAttempt(userId: String) {
        val attempts = failedAttempts.getOrPut(userId) { 0 } + 1
        failedAttempts[userId] = attempts

        if (attempts >= MAX_FAILED_ATTEMPTS) {
            lockoutTimestamps[userId] = System.currentTimeMillis()
        }
    }

    fun resetFailedAttempts(userId: String) {
        failedAttempts.remove(userId)
    }
}

sealed class RateLimitResult {
    object Allowed : RateLimitResult()
    data class ExceededPerMinute(val limit: Int) : RateLimitResult()
    data class ExceededPerHour(val limit: Int) : RateLimitResult()
    data class LockedOut(val remainingMs: Long) : RateLimitResult()
}

