// ============================================================
// Wallet Manager
// ============================================================

class WalletManager(
    private val context: Context,
    private val encryptionManager: SecureEncryptionManager,
    private val storageManager: SecureStorageManager,
    private val integrityChecker: DeviceIntegrityChecker,
    private val rateLimiter: TransactionRateLimiter
) {
    private val _walletState = MutableStateFlow<WalletState>(WalletState.Uninitialized)
    val walletState: StateFlow<WalletState> = _walletState.asStateFlow()

    private val transactionLog = mutableListOf<WalletTransaction>()
    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())

    companion object {
        private const val MAX_SINGLE_TRANSACTION = 10000.0
        private const val MAX_DAILY_TRANSACTION = 50000.0
    }

    suspend fun initializeWallet(userId: String): Result<BigDecimal> {
        return withContext(Dispatchers.IO) {
            try {
                // Check device trust
                val trustLevel = integrityChecker.assessTrustLevel()
                when (trustLevel) {
                    is DeviceTrustLevel.Untrusted -> {
                        _walletState.value = WalletState.Blocked("Device integrity check failed")
                        return@withContext Result.failure(
                            SecurityException.DeviceCompromised(
                                "Device is not trusted: ${trustLevel.reasons.joinToString()}"
                            )
                        )
                    }
                    is DeviceTrustLevel.Degraded -> {
                        Log.w("WalletManager", "Device has degraded trust: ${trustLevel.reasons}")
                        // Allow with restrictions
                    }
                    is DeviceTrustLevel.Trusted -> {
                        // Full access
                    }
                }

                val balance = storageManager.getWalletBalance(userId)
                _walletState.value = WalletState.Ready(userId, balance)
                Result.success(balance)
            } catch (e: Exception) {
                _walletState.value = WalletState.Error(e.message ?: "Unknown error")
                Result.failure(e)
            }
        }
    }

    suspend fun processTransaction(transaction: WalletTransaction): Result<PaymentResult> {
        return withContext(Dispatchers.IO) {
            try {
                // Validate device trust
                val trustLevel = integrityChecker.assessTrustLevel()
                if (trustLevel is DeviceTrustLevel.Untrusted) {
                    return@withContext Result.failure(
                        SecurityException.DeviceCompromised("Cannot process on untrusted device")
                    )
                }

                // Rate limiting
                when (val rateResult = rateLimiter.checkRateLimit(transaction.userId)) {
                    is RateLimitResult.Allowed -> { /* proceed */ }
                    is RateLimitResult.ExceededPerMinute -> {
                        return@withContext Result.failure(
                            SecurityException.RateLimitExceeded(
                                "Too many transactions. Limit: ${rateResult.limit}/minute"
                            )
                        )
                    }
                    is RateLimitResult.ExceededPerHour -> {
                        return@withContext Result.failure(
                            SecurityException.RateLimitExceeded(
                                "Too many transactions. Limit: ${rateResult.limit}/hour"
                            )
                        )
                    }
                    is RateLimitResult.LockedOut -> {
                        return@withContext Result.failure(
                            SecurityException.RateLimitExceeded(
                                "Account locked. Try again in ${rateResult.remainingMs / 1000}s"
                            )
                        )
                    }
                }

                // Validate transaction limits
                validateTransactionLimits(transaction)?.let { error ->
                    return@withContext Result.failure(error)
                }

                // Apply degraded mode restrictions
                if (trustLevel is DeviceTrustLevel.Degraded) {
                    val degradedLimit = BigDecimal("100.00")
                    if (transaction.amount > degradedLimit) {
                        return@withContext Result.failure(
                            SecurityException.TransactionLimitExceeded(
                                "Transaction limit reduced to $degradedLimit on this device"
                            )
                        )
                    }
                }

                // Process the transaction
                val currentBalance = storageManager.getWalletBalance(transaction.userId)
                val newBalance = when (transaction.type) {
                    TransactionType.CREDIT, TransactionType.REFUND, TransactionType.TRANSFER_IN -> {
                        currentBalance + transaction.amount
                    }
                    TransactionType.DEBIT, TransactionType.PURCHASE, TransactionType.TRANSFER_OUT -> {
                        if (currentBalance < transaction.amount) {
                            rateLimiter.recordFailedAttempt(transaction.userId)
                            return@withContext Result.failure(
                                SecurityException.TransactionLimitExceeded("Insufficient balance")
                            )
                        }
                        currentBalance - transaction.amount
                    }
                }

                // Store updated balance
                storageManager.storeWalletBalance(transaction.userId, newBalance)

                // Log transaction (encrypted)
                val completedTransaction = transaction.copy(status = TransactionStatus.COMPLETED)
                logTransaction(completedTransaction)

                rateLimiter.recordTransaction(transaction.userId)
                rateLimiter.resetFailedAttempts(transaction.userId)

                _walletState.value = WalletState.Ready(transaction.userId, newBalance)

                Result.success(
                    PaymentResult(
                        success = true,
                        transactionId = transaction.id,
                        message = "Transaction completed successfully"
                    )
                )
            } catch (e: SecurityException) {
                rateLimiter.recordFailedAttempt(transaction.userId)
                Result.failure(e)
            } catch (e: Exception) {
                Result.failure(
                    SecurityException.EncryptionError(e.message ?: "Transaction processing failed")
                )
            }
        }
    }

    private fun validateTransactionLimits(transaction: WalletTransaction): SecurityException? {
        if (transaction.amount <= BigDecimal.ZERO) {
            return SecurityException.TransactionLimitExceeded("Amount must be positive")
        }

        if (transaction.amount > BigDecimal(MAX_SINGLE_TRANSACTION)) {
            return SecurityException.TransactionLimitExceeded(
                "Single transaction limit: $MAX_SINGLE_TRANSACTION"
            )
        }

        // Check daily limit
        val today = System.currentTimeMillis()
        val dayStart = today - (today % (24 * 60 * 60 * 1000))
        val dailyTotal = transactionLog
            .filter { it.userId == transaction.userId && it.timestamp >= dayStart }
            .fold(BigDecimal.ZERO) { acc, t -> acc + t.amount }

        if (dailyTotal + transaction.amount > BigDecimal(MAX_DAILY_TRANSACTION)) {
            return SecurityException.TransactionLimitExceeded(
                "Daily transaction limit: $MAX_DAILY_TRANSACTION"
            )
        }

        return null
    }

    private fun logTransaction(transaction: WalletTransaction) {
        transactionLog.add(transaction)

        // Encrypt and store transaction log entry
        val transactionData = "${transaction.id}|${transaction.type}|${transaction.amount}|${transaction.timestamp}|${transaction.status}"
        val encrypted = encryptionManager.encryptString(transactionData)
        storageManager.storeSecurely("tx_${transaction.id}", encrypted)
    }

    fun getTransactionHistory(userId: String): List<WalletTransaction> {
        return transactionLog.filter { it.userId == userId }.sortedByDescending { it.timestamp }
    }

    fun destroy() {
        scope.cancel()
    }
}

sealed class WalletState {
    object Uninitialized : WalletState()
    data class Ready(val userId: String, val balance: BigDecimal) : WalletState()
    data class Error(val message: String) : WalletState()
    data class Blocked(val reason: String) : WalletState()
}

// ============================================================
// In-App Purchase Manager (Google Play Billing)
// ============================================================

class InAppPurchaseManager(
    private val context: Context,
    private val integrityChecker: DeviceIntegrityChecker,
    private val encryptionManager: SecureEncryptionManager,
    private val rateLimiter: TransactionRateLimiter
) : PurchasesUpdatedListener {

    private var billingClient: BillingClient? = null
    private val _purchaseState = MutableStateFlow<PurchaseState>(PurchaseState.Idle)
    val purchaseState: StateFlow<PurchaseState> = _purchaseState.asStateFlow()

    private var pendingPurchaseCallback: ((Result<Purchase>) -> Unit)? = null
    private val scope = CoroutineScope(Dispatchers.Main + SupervisorJob())

    fun initialize() {
        billingClient = BillingClient.newBuilder(context)
            .setListener(this)
            .enablePendingPurchases()
            .build()

        connectToPlayBilling()
    }

    private fun connectToPlayBilling() {
        billingClient?.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingResult) {
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    _purchaseState.value = PurchaseState.Connected
                    Log.d("InAppPurchase", "Billing client connected")
                } else {
                    _purchaseState.value = PurchaseState.Error(
                        "Billing setup failed: ${billingResult.debugMessage}"
                    )
                }
            }

            override fun onBillingServiceDisconnected() {
                _purchaseState.value = PurchaseState.Disconnected
                // Retry connection with exponential backoff
                scope.launch {
                    delay(3000)
                    connectToPlayBilling()
                }
            }
        })
    }

    suspend fun queryProducts(
        productIds: List<String>,
        productType: String = BillingClient.ProductType.INAPP
    ): Result<List<ProductDetails>> {
        // Check device trust before allowing purchases
        val trustLevel = integrityChecker.assessTrustLevel()
        if (trustLevel is DeviceTrustLevel.Untrusted) {
            return Result.failure(
                SecurityException.DeviceCompromised("Purchases blocked on untrusted device")
            )
        }

        val client = billingClient ?: return Result.failure(
            IllegalStateException("Billing client not initialized")
        )

        val productList = productIds.map { productId ->
            QueryProductDetailsParams.Product.newBuilder()
                .setProductId(productId)
                .setProductType(productType)
                .build()
        }

        val params = QueryProductDetailsParams.newBuilder()
            .setProductList(productList)
            .build()

        return withContext(Dispatchers.IO) {
            val result = CompletableDeferred<Result<List<ProductDetails>>>()

            client.queryProductDetailsAsync(params) { billingResult, productDetailsList ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    result.complete(Result.success(productDetailsList))
                } else {
                    result.complete(Result.failure(
                        Exception("Query failed: ${billingResult.debugMessage}")
                    ))
                }
            }

            result.await()
        }
    }

    fun launchPurchaseFlow(
        activity: FragmentActivity,
        productDetails: ProductDetails,
        userId: String,
        callback: (Result<Purchase>) -> Unit
    ) {
        // Rate limit check
        when (val rateResult = rateLimiter.checkRateLimit(userId)) {
            is RateLimitResult.Allowed -> { /* proceed */ }
            else -> {
                callback(Result.failure(
                    SecurityException.RateLimitExceeded("Purchase rate limit exceeded")
                ))
                return
            }
        }

        val trustLevel = integrityChecker.assessTrustLevel()
        if (trustLevel is DeviceTrustLevel.Untrusted) {
            callback(Result.failure(
                SecurityException.DeviceCompromised("Cannot purchase on untrusted device")
            ))
            return
        }

        pendingPurchaseCallback = callback

        val offerToken = productDetails.subscriptionOfferDetails?.firstOrNull()?.offerToken

        val productDetailsParamsBuilder = BillingFlowParams.ProductDetailsParams.newBuilder()
            .setProductDetails(productDetails)

        if (offerToken != null) {
            productDetailsParamsBuilder.setOfferToken(offerToken)
        }

        val billingFlowParams = BillingFlowParams.newBuilder()
            .setProductDetailsParamsList(listOf(productDetailsParamsBuilder.build()))
            .setObfuscatedAccountId(encryptionManager.hashSensitiveData(userId))
            .build()

        billingClient?.launchBillingFlow(activity, billingFlowParams)
    }

    override fun onPurchasesUpdated(
        billingResult: BillingResult,
        purchases: MutableList<Purchase>?
    ) {
        when (billingResult.responseCode) {
            BillingClient.BillingResponseCode.OK -> {
                purchases?.forEach { purchase ->
                    scope.launch {
                        handlePurchase(purchase)
                    }
                }
            }
            BillingClient.BillingResponseCode.USER_CANCELED -> {
                _purchaseState.value = PurchaseState.Cancelled
                pendingPurchaseCallback?.invoke(
                    Result.failure(Exception("Purchase cancelled by user"))
                )
            }
            else -> {
                _purchaseState.value = PurchaseState.Error(billingResult.debugMessage)
                pendingPurchaseCallback?.invoke(
                    Result.failure(Exception("Purchase failed: ${billingResult.debugMessage}"))
                )
            }
        }
        pendingPurchaseCallback = null
    }

    private suspend fun handlePurchase(purchase: Purchase) {
        if (purchase.purchaseState == Purchase.PurchaseState.PURCHASED) {
            // Verify purchase on server side (critical for security)
            val verified = verifyPurchaseOnServer(purchase)

            if (verified) {
                // Acknowledge the purchase
                if (!purchase.isAcknowledged) {
                    val acknowledgePurchaseParams = AcknowledgePurchaseParams.newBuilder()
                        .setPurchaseToken(purchase.purchaseToken)
                        .build()

                    val result = CompletableDeferred<Boolean>()
                    billingClient?.acknowledgePurchase(acknowledgePurchaseParams) { billingResult ->
                        result.complete(billingResult.responseCode == BillingClient.BillingResponseCode.OK)
                    }

                    if (result.await()) {
                        _purchaseState.value = PurchaseState.Completed(purchase)
                        // Store purchase record securely
                        storePurchaseRecord(purchase)
                    }
                }

                pendingPurchaseCallback?.invoke(Result.success(purchase))
            } else {
                _purchaseState.value = PurchaseState.Error("Purchase verification failed")
                pendingPurchaseCallback?.invoke(
                    Result.failure(SecurityException.IntegrityCheckFailed("Purchase verification failed"))
                )
            }
        } else if (purchase.purchaseState == Purchase.PurchaseState.PENDING) {
            _purchaseState.value = PurchaseState.Pending(purchase)
        }
    }

    private suspend fun verifyPurchaseOnServer(purchase: Purchase): Boolean {
        // In production, send purchase.purchaseToken to your backend server
        // for verification with Google Play Developer API
        // This is a critical security step - never trust client-side verification alone

        return withContext(Dispatchers.IO) {
            try {
                // Verify purchase signature locally as a first check
                val signatureValid = verifyPurchaseSignature(
                    purchase.originalJson,
                    purchase.signature
                )

                if (!signatureValid) {
                    Log.e("InAppPurchase", "Local signature verification failed")
                    return@withContext false
                }

                // TODO: Send to backend for server-side verification
                // val response = apiService.verifyPurchase(
                //     purchaseToken = purchase.purchaseToken,
                //     productId = purchase.products.firstOrNull() ?: "",
                //     packageName = context.packageName
                // )
                // return@withContext response.isValid

                true // Placeholder - MUST implement server verification
            } catch (e: Exception) {
                Log.e("InAppPurchase", "Verification error", e)
                false
            }
        }
    }

    private fun verifyPurchaseSignature(signedData: String, signature: String): Boolean {
        // Verify using your app's public key from Google Play Console
        // This is a basic check - server-side verification is essential
        return try {
            if (signedData.isEmpty() || signature.isEmpty()) {
                return false
            }
            // In production, use your actual base64-encoded RSA public key
            // from Google Play Console
            true // Placeholder
        } catch (e: Exception) {
            false
        }
    }

    private fun storePurchaseRecord(purchase: Purchase) {
        val purchaseData = "${purchase.orderId}|${purchase.products}|${purchase.purchaseTime}"
        val encrypted = encryptionManager.encryptString(purchaseData)
        // Store encrypted purchase record
    }

    suspend fun consumePurchase(purchase: Purchase): Result<Unit> {
        val client = billingClient ?: return Result.failure(
            IllegalStateException("Billing client not initialized")
        )

        val consumeParams = ConsumeParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        return withContext(Dispatchers.IO) {
            val result = CompletableDeferred<Result<Unit>>()

            client.consumeAsync(consumeParams) { billingResult, _ ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    result.complete(Result.success(Unit))
                } else {
                    result.complete(Result.failure(
                        Exception("Consume failed: ${billingResult.debugMessage}")
                    ))
                }
            }

            result.await()
        }
    }

    suspend fun restorePurchases(): Result<List<Purchase>> {
        val client = billingClient ?: return Result.failure(
            IllegalStateException("Billing client not initialized")
        )

        return withContext(Dispatchers.IO) {
            val result = CompletableDeferred<Result<List<Purchase>>>()

            val params = QueryPurchasesParams.newBuilder()
                .setProductType(BillingClient.ProductType.INAPP)
                .build()

            client.queryPurchasesAsync(params) { billingResult, purchases ->
                if (billingResult.responseCode == BillingClient.BillingResponseCode.OK) {
                    result.complete(Result.success(purchases))
                } else {
                    result.complete(Result.failure(
                        Exception("Restore failed: ${billingResult.debugMessage}")
                    ))
                }
            }

            result.await()
        }
    }

    fun destroy() {
        billingClient?.endConnection()
        billingClient = null
        scope.cancel()
    }
}

sealed class PurchaseState {
    object Idle : PurchaseState()
    object Connected : PurchaseState()
    object Disconnected : PurchaseState()
    data class Completed(val purchase: Purchase) : PurchaseState()
    data class Pending(val purchase: Purchase) : PurchaseState()
    object Cancelled : PurchaseState()
    data class Error(val message: String) : PurchaseState()
}

// ============================================================
// Payment Processing Facade
// ============================================================

class PaymentProcessor private constructor(
    private val context: Context,
    private val integrityChecker: DeviceIntegrityChecker,
    private val encryptionManager: SecureEncryptionManager,
    private val storageManager: SecureStorageManager,
    private val walletManager: WalletManager,
    private val inAppPurchaseManager: InAppPurchaseManager,
    private val rateLimiter: TransactionRateLimiter,
    private val biometricAuthManager: BiometricAuthManager?
) {

    companion object {
        @Volatile
        private var instance: PaymentProcessor? = null

        fun initialize(activity: FragmentActivity): PaymentProcessor {
            return instance ?: synchronized(this) {
                instance ?: buildProcessor(activity).also { instance = it }
            }
        }

        fun getInstance(): PaymentProcessor {
            return instance ?: throw IllegalStateException(
                "PaymentProcessor not initialized. Call initialize() first."
            )
        }

        private fun buildProcessor(activity: FragmentActivity): PaymentProcessor {
            val context = activity.applicationContext
            val integrityChecker = DeviceIntegrityChecker(context)
            val encryptionManager = SecureEncryptionManager(context)
            val storageManager = SecureStorageManager(context)
            val rateLimiter = TransactionRateLimiter()
            val biometricAuthManager = BiometricAuthManager(activity)

            val walletManager = WalletManager(
                context, encryptionManager, storageManager, integrityChecker, rateLimiter
            )

            val inAppPurchaseManager = InAppPurchaseManager(
                context, integrityChecker, encryptionManager, rateLimiter
            )

            return PaymentProcessor(
                context, integrityChecker, encryptionManager, storageManager,
                walletManager, inAppPurchaseManager, rateLimiter, biometricAuthManager
            )
        }
    }

    fun initializeBilling() {
        inAppPurchaseManager.initialize()
    }

    suspend fun initializeWallet(userId: String): Result<BigDecimal> {
        return walletManager.initializeWallet(userId)
    }

    fun getDeviceTrustLevel(): DeviceTrustLevel {
        return integrityChecker.assessTrustLevel()
    }

    fun requireBiometricAuth(
        activity: FragmentActivity,
        onAuthenticated: () -> Unit,
        onError: (String) -> Unit
    ) {
        val authManager = BiometricAuthManager(activity)
        authManager.authenticate(
            title = "Verify Payment",
            subtitle = "Authenticate to proceed with payment",
            onSuccess = onAuthenticated,
            onError = { _, message -> onError(message) },
            onFailed = { onError("Authentication failed") }
        )
    }

    suspend fun processWalletTransaction(
        userId: String,
        amount: BigDecimal,
        type: TransactionType,
        description: String,
        requireAuth: Boolean = true,
        activity: FragmentActivity? = null
    ): Result<PaymentResult> {
        // For high-value transactions, require biometric auth
        if (requireAuth && amount > BigDecimal("50.00") && activity != null) {
            val authResult = CompletableDeferred<Boolean>()
            val authManager = BiometricAuthManager(activity)

            withContext(Dispatchers.Main) {
                authManager.authenticate(
                    title = "Confirm Payment",
                    subtitle = "Authenticate to confirm ${amount.toPlainString()} $type",
                    onSuccess = { authResult.complete(true) },
                    onError = { _, _ -> authResult.complete(false) },
                    onFailed = { authResult.complete(false) }
                )
            }

            if (!authResult.await()) {
                return Result.failure(
                    SecurityException.AuthenticationRequired("Biometric authentication required")
                )
            }
        }

        val transaction = WalletTransaction(
            userId = userId,
            type = type,
            amount = amount,
            description = description
        )

        return walletManager.processTransaction(transaction)
    }

    suspend fun queryInAppProducts(productIds: List<String>): Result<List<ProductDetails>> {
        return inAppPurchaseManager.queryProducts(productIds)
    }

    fun launchPurchase(
        activity: FragmentActivity,
        productDetails: ProductDetails,
        userId: String,
        callback: (Result<Purchase>) -> Unit
    ) {
        inAppPurchaseManager.launchPurchaseFlow(activity, productDetails, userId, callback)
    }

    suspend fun consumePurchase(purchase: Purchase): Result<Unit> {
        return inAppPurchaseManager.consumePurchase(purchase)
    }

    suspend fun restorePurchases(): Result<List<Purchase>> {
        return inAppPurchaseManager.restorePurchases()
    }

    fun getWalletState(): StateFlow<WalletState> = walletManager.walletState
    fun getPurchaseState(): StateFlow<PurchaseState> = inAppPurchaseManager.purchaseState

    fun getTransactionHistory(userId: String): List<WalletTransaction> {
        return walletManager.getTransactionHistory(userId)
    }

    fun encryptSensitiveData(data: String): String {
        return encryptionManager.encryptString(data)
    }

    fun decryptSensitiveData(encryptedData: String): String {
        return encryptionManager.decryptString(encryptedData)
    }

    fun securelyStore(key: String, value: String) {
        storageManager.storeSecurely(key, value)
    }

    fun securelyRetrieve(key: String): String? {
        return storageManager.retrieveSecurely(key)
    }

    fun destroy() {
        walletManager.destroy()
        inAppPurchaseManager.destroy()
        instance = null
    }
}

// ============================================================
// Anti-Tampering Monitor
// ============================================================

class AntiTamperingMonitor(private val context: Context) {

    private val expectedSignatureHash: String? = null // Set in production

    fun verifyAppIntegrity(): Boolean {
        return !isAppTampered() && !isRunningInDebugger() && verifyInstaller()
    }

    private fun isAppTampered(): Boolean {
        try {
            val packageInfo = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                context.packageManager.getPackageInfo(
                    context.packageName,
                    android.content.pm.PackageManager.GET_SIGNING_CERTIFICATES
                )
            } else {
                @Suppress("DEPRECATION")
                context.packageManager.getPackageInfo(
                    context.packageName,
                    android.content.pm.PackageManager.GET_SIGNATURES
                )
            }

            val signatures = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
                packageInfo.signingInfo?.apkContentsSigners
            } else {
                @Suppress("DEPRECATION")
                packageInfo.signatures
            }

            if (signatures.isNullOrEmpty()) return true

            // Verify signature hash matches expected
            for (signature in signatures) {
                val digest = MessageDigest.getInstance("SHA-256")
                val hash = digest.digest(signature.toByteArray())
                val hashString = Base64.encodeToString(hash, Base64.NO_WRAP)

                if (expectedSignatureHash != null && hashString != expectedSignatureHash) {
                    return true
                }
            }

            return false
        } catch (e: Exception) {
            return true // Assume tampered if we can't verify
        }
    }

    private fun isRunningInDebugger(): Boolean {
        return android.os.Debug.isDebuggerConnected() || android.os.Debug.waitingForDebugger()
    }

    private fun verifyInstaller(): Boolean {
        val validInstallers = listOf(
            "com.android.vending",      // Google Play Store
            "com.google.android.feedback" // Google Play Store (alternative)
        )

        val installer = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.R) {
            context.packageManager.getInstallSourceInfo(context.packageName).installingPackageName
        } else {
            @Suppress("DEPRECATION")
            context.packageManager.getInstallerPackageName(context.packageName)
        }

        // In debug builds, allow null installer
        if (installer == null) {
            return (context.applicationInfo.flags and android.content.pm.ApplicationInfo.FLAG_DEBUGGABLE) != 0
        }

        return installer in validInstallers
    }
}

// ============================================================
// Secure Network Communication Helper
// ============================================================

class SecureNetworkConfig {
    companion object {
        fun createSecureOkHttpConfig(): Map<String, Any> {
            return mapOf(
                "certificatePinning" to true,
                "tlsVersion" to "TLSv1.3",
                "connectionTimeout" to 30000,
                "readTimeout" to 30000,
                "retryOnConnectionFailure" to true,
                "followRedirects" to false
            )
        }

        fun generateRequestNonce(): String {
            val bytes = ByteArray(32)
            SecureRandom().nextBytes(bytes)
            return Base64.encodeToString(bytes, Base64.NO_WRAP)
        }

        fun generateIdempotencyKey(): String {
            return UUID.randomUUID().toString()
        }
    }
}